  /** Custom generators for specific schema properties. */
  export interface CustomMap {
    string?: (
      schema: OpenApi.IJsonSchema.IString & Record<string, any>,
    ) => string;
    number?: (
      schema: OpenApi.IJsonSchema.INumber & Record<string, any>,
