    (doc: OpenApiV3_2.IDocument) =>
    (pathItem: OpenApiV3_2.IPath): OpenApi.IPath => {
      const { parameters: _parameters, ...rest } = pathItem as any;
      return {
        ...rest,
        ...(pathItem.get
          ? { get: convertOperation(doc)(pathItem)(pathItem.get) }
          : undefined),
        ...(pathItem.put
          ? { put: convertOperation(doc)(pathItem)(pathItem.put) }
          : undefined),
        ...(pathItem.post
          ? { post: convertOperation(doc)(pathItem)(pathItem.post) }
          : undefined),
        ...(pathItem.delete
          ? { delete: convertOperation(doc)(pathItem)(pathItem.delete) }
          : undefined),
        ...(pathItem.options
          ? { options: convertOperation(doc)(pathItem)(pathItem.options) }
          : undefined),
        ...(pathItem.head
          ? { head: convertOperation(doc)(pathItem)(pathItem.head) }
          : undefined),
        ...(pathItem.patch
          ? { patch: convertOperation(doc)(pathItem)(pathItem.patch) }
          : undefined),
        ...(pathItem.trace
          ? { trace: convertOperation(doc)(pathItem)(pathItem.trace) }
          : undefined),
        ...(pathItem.query
          ? { query: convertOperation(doc)(pathItem)(pathItem.query) }
          : undefined),
        ...(pathItem.additionalOperations
          ? {
              additionalOperations: Object.fromEntries(
                Object.entries(pathItem.additionalOperations)
                  .filter(([_, v]) => v !== undefined)
                  .map(
                    ([key, value]) =>
                      [key, convertOperation(doc)(pathItem)(value)] as const,
                  ),
              ),
            }
          : undefined),
      };
    };

  const convertOperation =
    (doc: OpenApiV3_2.IDocument) =>
    (pathItem: OpenApiV3_2.IPath) =>
    (input: OpenApiV3_2.IOperation): OpenApi.IOperation => {
      const components: OpenApiV3_2.IComponents = doc.components ?? {};
      const pathParameters: OpenApiV3_2.IOperation.IParameter[] = (
        pathItem.parameters ?? []
      )
        .map(resolveParameter(components))
        .filter((p): p is OpenApiV3_2.IOperation.IParameter => p !== undefined);
      const operationParameters: OpenApiV3_2.IOperation.IParameter[] = (
        input.parameters ?? []
      )
        .map(resolveParameter(components))
        .filter((p): p is OpenApiV3_2.IOperation.IParameter => p !== undefined);
      return {
        ...input,
        parameters:
          pathItem.parameters !== undefined || input.parameters !== undefined
            ? mergeParameters(pathParameters, operationParameters).map(
                convertParameter(components),
              )
            : undefined,
        requestBody: input.requestBody
          ? convertRequestBody(doc)(input.requestBody)
          : undefined,
        responses: input.responses
          ? Object.fromEntries(
              Object.entries(input.responses)
                .filter(([_, v]) => v !== undefined)
                .map(
                  ([key, value]) =>
                    [key, convertResponse(doc)(value)!] as const,
                )
                .filter(([_, value]) => value !== undefined),
            )
          : undefined,
      };
    };

  const resolveParameter =
    (components: OpenApiV3_2.IComponents) =>
    (
      input:
        | OpenApiV3_2.IOperation.IParameter
        | OpenApiV3_2.IJsonSchema.IReference<`#/components/headers/${string}`>
        | OpenApiV3_2.IJsonSchema.IReference<`#/components/parameters/${string}`>,
    ): OpenApiV3_2.IOperation.IParameter | undefined => {
      if (!("$ref" in input)) return input;
      const key: string = input.$ref.split("/").pop() ?? "";
      if (input.$ref.startsWith("#/components/headers/")) {
