import { spawnSync } from "node:child_process";
import fs from "node:fs";

/**
 * Spawn a native binary (or a Node.js script when the path has a JS/TS
 * extension) with the given args and return the `spawnSync` result. Sets a
 * generous 256 MiB output buffer so large projects do not truncate.
 *
 * When `options.encoding` is omitted it defaults to `"utf8"`. Pass an explicit
 * value when the caller needs a different encoding or raw `Buffer` output.
 */
export function spawnNative(
  binary: string,
  args: readonly string[],
  options: {
    cwd?: string;
    env?: NodeJS.ProcessEnv;
    encoding?: BufferEncoding;
  },
) {
  const viaNode = /\.(?:[cm]?js|ts)$/i.test(binary);
  if (!viaNode) {
    ensureExecutable(binary);
  }
  return spawnSync(
    viaNode ? process.execPath : binary,
    viaNode ? [binary, ...args] : [...args],
    {
      cwd: options.cwd,
      encoding: options.encoding ?? "utf8",
      env: options.env,
      maxBuffer: 1024 * 1024 * 256,
      windowsHide: true,
    },
  );
}

/**
 * Ensure the binary has the executable bit set on POSIX systems. Silently skips
 * on Windows and swallows `chmod` errors to let the original spawn error
 * surface instead of masking it with a permission error.
 */
export function ensureExecutable(binary: string): void {
  if (process.platform === "win32") {
    return;
  }
  try {
    fs.accessSync(binary, fs.constants.X_OK);
    return;
  } catch {
    try {
      const mode = fs.statSync(binary).mode & 0o777;
      fs.chmodSync(binary, mode | 0o755);
    } catch {
      /* keep the original spawn error path */
    }
  }
}

/** Coerce a `spawnSync` output value to a plain string, defaulting to `""`. */
export function outputText(value: string | Buffer | null | undefined): string {
  if (value == null) {
    return "";
  }
  return typeof value === "string" ? value : value.toString("utf8");
}

ttsc/src/compiler/internal/startResident:
import path from "node:path";

import { loadProjectPlugins } from "../../plugin/internal/loadProjectPlugins";
import type { ITtscCompilerContext } from "../../structures/ITtscCompilerContext";
import type { ITtscLoadedNativePlugin } from "../../structures/internal/ITtscLoadedNativePlugin";
import { readProjectConfig } from "./project/readProjectConfig";
import { ResidentTransformProcess } from "./residentTransformProcess";
import { resolveBinary } from "./resolveBinary";
import { resolveTsgo } from "./resolveTsgo";
import {
  assertSharedHostCompatibility,
  linkedTransformPlugins,
  resolvePluginConfigDir,
  selectSharedHostPlugin,
} from "./sharedHostHelpers";

/**
 * A started resident transform host plus the project root its keys are relative
 * to.
 */
export interface StartedResidentTransform {
  process: ResidentTransformProcess;
  projectRoot: string;
}

/**
 * Start a resident `serve` host for the configured project.
 *
 * Mirrors the plugin spawn of `transformProjectInMemory`, but launches the
 * shared host's `serve` subcommand as one long-lived process instead of a
 * per-call `transform` subprocess. The host compiles the whole project once at
 * startup and then answers per-file requests, so one caller pays the project
 * compile once and reuses it across its own per-file requests.
 *
 * Resident mode runs through the linked-plugin shared host
 * (`cmd/utility-host`), which is the only binary that exposes `serve`. It
 * therefore requires at least one transform-stage plugin; executable transform
 * hosts that own their own process are not served and must use the per-call
 * transform path. Check-stage plugins are not run by the resident host.
 */
export function startResidentTransform(
  context: ITtscCompilerContext,
): StartedResidentTransform {
  const cwd = path.resolve(context.cwd ?? process.cwd());
  const project = readProjectConfig({
    cwd,
    projectRoot: context.projectRoot,
    tsconfig: context.tsconfig,
  });
  const loaded = loadProjectPlugins({
    binary: resolveBinary(context) ?? "",
    cacheDir: context.cacheDir ?? context.env?.TTSC_CACHE_DIR,
    cwd,
    entries: context.plugins,
    env: { ...process.env, ...context.env },
    pluginConfigDir: context.pluginConfigDir,
    projectRoot: context.projectRoot,
    tsconfig: project.path,
  });
  const transformers = loaded.nativePlugins.filter(
    (plugin) => plugin.stage === "transform",
  );
  if (transformers.length === 0) {
    throw new Error(
      "ttsc: TtscService resident mode requires at least one transform-stage plugin; " +
        "use TtscCompiler.transform for projects with only check-stage plugins or none",
    );
  }
  assertSharedHostCompatibility(transformers, "source-to-source");

  const host = selectSharedHostPlugin(transformers);
  const tsgoBinary = resolveTsgo({ ...context, cwd: project.root }).binary;
  const resident = new ResidentTransformProcess({
    args: [
      "serve",
      `--tsconfig=${project.path}`,
      `--plugins-json=${serializeNativePlugins(transformers)}`,
      `--cwd=${project.root}`,
    ],
    binary: host.binary,
    cwd: project.root,
    env: residentEnv(context, tsgoBinary, loaded.nativePlugins),
  });
  return { process: resident, projectRoot: project.root };
}

/**
 * Build the environment for the resident host spawn. Matches the per-call
 * transform spawn: injects the Node, tsgo, and ttsx binaries so the host never
 * searches PATH, sets `TTSC_PLUGIN_CONFIG_DIR` when the caller declared a
 * plugin config anchor (an embedder compiling through a generated wrapper
 * tsconfig) so config-file discovery walks the real project instead of the
 * wrapper's temp-dir ancestry, and forwards linked transform plugins via
 * `TTSC_LINKED_PLUGINS_JSON`.
 */
function residentEnv(
  context: ITtscCompilerContext,
  tsgoBinary: string,
  nativePlugins: readonly ITtscLoadedNativePlugin[],
): NodeJS.ProcessEnv {
  const pluginConfigDir = resolvePluginConfigDir(context);
  const env: NodeJS.ProcessEnv = {
    ...process.env,
    TTSC_NODE_BINARY: process.env.TTSC_NODE_BINARY ?? process.execPath,
    ...(pluginConfigDir === undefined
      ? {}
      : { TTSC_PLUGIN_CONFIG_DIR: pluginConfigDir }),
    TTSC_TSGO_BINARY: process.env.TTSC_TSGO_BINARY ?? tsgoBinary,
    TTSC_TTSX_BINARY:
      process.env.TTSC_TTSX_BINARY ??
      path.join(__dirname, "..", "..", "launcher", "ttsx.js"),
    ...context.env,
  };
  // The anchor is per-invocation state owned by this host: when this run
  // declared none (and the caller's env does not name one), drop any value
  // inherited from an ancestor ttsc process so a nested build never
  // mis-anchors its plugins at the outer project.
  if (
    pluginConfigDir === undefined &&
    context.env?.TTSC_PLUGIN_CONFIG_DIR === undefined
  ) {
    delete env.TTSC_PLUGIN_CONFIG_DIR;
  }
  const linked = linkedTransformPlugins(nativePlugins);
  if (linked.length !== 0) {
    env.TTSC_LINKED_PLUGINS_JSON = serializeNativePlugins(linked);
  }
  return env;
}

/**
 * Serialize the plugin list to the `--plugins-json` /
 * `TTSC_LINKED_PLUGINS_JSON` shape the native host reads: only the fields it
 * needs, to keep the arg short.
 */
function serializeNativePlugins(
  plugins: readonly ITtscLoadedNativePlugin[],
): string {
  return JSON.stringify(
    plugins.map((plugin) => ({
      config: plugin.config,
      name: plugin.name,
      stage: plugin.stage,
    })),
  );
}

ttsc/src/compiler/internal/transformProj:
import path from "node:path";

import {
  hasProjectPluginEntries,
  loadProjectPlugins,
} from "../../plugin/internal/loadProjectPlugins";
import type { ITtscCompilerContext } from "../../structures/ITtscCompilerContext";
import type { ITtscCompilerDiagnostic } from "../../structures/ITtscCompilerDiagnostic";
import type { ITtscCompilerTransformation } from "../../structures/ITtscCompilerTransformation";
import type { ITtscLoadedNativePlugin } from "../../structures/internal/ITtscLoadedNativePlugin";
import type { ITtscParsedProjectConfig } from "../../structures/internal/ITtscParsedProjectConfig";
import type { TtscBuildResult } from "../../structures/internal/TtscBuildResult";
import { buildNativeCompiler } from "./buildNativeCompiler";
import { packageRootDir } from "./paths";
import { createNativeProjectContextArgs } from "./project/createNativeProjectContextArgs";
import { readProjectConfig } from "./project/readProjectConfig";
import { resolveBinary } from "./resolveBinary";
import { resolveTsgo } from "./resolveTsgo";
import { appendBuildOutput, normalizeBuildOutput } from "./runBuild";
import {
  assertSharedHostCompatibility,
  linkedTransformPlugins,
  resolvePluginConfigDir,
  selectSharedHostPlugin,
} from "./sharedHostHelpers";
import { outputText, spawnNative } from "./spawnNative";

/**
 * Transform a project and capture TypeScript source output in memory.
 *
 * When no plugins are configured the fast path spawns the native ttsc compiler
 * host (`cmd/ttsc api-transform`) which returns a JSON map of transformed
 * TypeScript sources. When plugins are present:
 *
 * 1. Check-stage plugins run first and abort on failure.
 * 2. If there are no transform-stage plugins the host is used as the transformer.
 * 3. If transform plugins exist they are dispatched through the shared-host binary
 *    with linked plugins passed via `TTSC_LINKED_PLUGINS_JSON`.
 *
 * @returns A `{ result, typescript }` pair where `typescript` maps output paths
 *   to their transformed TypeScript source text.
 */
export function transformProjectInMemory(options: ITtscCompilerContext): {
  dependencies?: Record<string, string[]>;
  dependenciesComplete?: string[];
  graph?: ITtscCompilerTransformation.IReferenceGraph;
  result: TtscBuildResult;
  typescript: Record<string, string>;
  volatile?: string[];
} {
  const cwd = path.resolve(options.cwd ?? process.cwd());
  const project = readProjectConfig({
    cwd,
    projectRoot: options.projectRoot,
    tsconfig: options.tsconfig,
  });
  if (hasConfiguredPlugins(options, project)) {
    return transformProjectWithPlugins(options, cwd, project);
  }
  return transformProjectWithNativeHost(options, project);
}

/** Return true when the project or the call-level options declare any plugins. */
function hasConfiguredPlugins(
  options: ITtscCompilerContext,
  project: ITtscParsedProjectConfig,
): boolean {
  return hasProjectPluginEntries(project, options.plugins);
}

/**
 * Transform via the built-in native compiler host (`cmd/ttsc api-transform`).
 * Used when no user plugins are configured, or as the fallback transformer when
 * check-stage plugins pass and no transform-stage plugins are declared.
 */
function transformProjectWithNativeHost(
  options: ITtscCompilerContext,
  project: ITtscParsedProjectConfig,
): {
  dependencies?: Record<string, string[]>;
  dependenciesComplete?: string[];
  graph?: ITtscCompilerTransformation.IReferenceGraph;
  result: TtscBuildResult;
  typescript: Record<string, string>;
  volatile?: string[];
} {
  const binary = buildNativeCompiler({
    cacheBaseDir: project.root,
    cacheDir: options.cacheDir ?? options.env?.TTSC_CACHE_DIR,
    packageRoot: packageRootDir(),
  });
  const res = spawnNative(
    binary,
    ["api-transform", "--cwd", project.root, "--tsconfig", project.path],
    {
      cwd: project.root,
      env: { ...process.env, ...options.env },
    },
  );
  if (res.error) {
    throw new Error(
      `ttsc: failed to spawn native compiler host ${binary}: ${res.error.message}`,
    );
  }

  const output = parseNativeTransformOutput(
    outputText(res.stdout),
    outputText(res.stderr),
  );
  return {
    ...envelopeSideChannels(output),
    result: {
      diagnostics: output.diagnostics,
      status: res.status ?? 1,
      stdout: "",
      stderr: outputText(res.stderr),
    },
    typescript: output.typescript,
  };
}

function transformProjectWithPlugins(
  options: ITtscCompilerContext,
  cwd: string,
  project: ITtscParsedProjectConfig,
): {
  dependencies?: Record<string, string[]>;
  dependenciesComplete?: string[];
  graph?: ITtscCompilerTransformation.IReferenceGraph;
  result: TtscBuildResult;
  typescript: Record<string, string>;
  volatile?: string[];
} {
  const loaded = loadProjectPlugins({
    binary: resolveBinary(options) ?? "",
    cacheDir: options.cacheDir ?? options.env?.TTSC_CACHE_DIR,
    cwd,
    entries: options.plugins,
    env: { ...process.env, ...options.env },
    pluginConfigDir: options.pluginConfigDir,
    projectRoot: options.projectRoot,
    tsconfig: project.path,
  });
  const checks = loaded.nativePlugins.filter(
    (plugin) => plugin.stage === "check",
  );
  const transformers = loaded.nativePlugins.filter(
    (plugin) => plugin.stage === "transform",
  );
  const tsgoBinary =
    loaded.nativePlugins.length === 0
      ? ""
      : resolveTsgo({ ...options, cwd: project.root }).binary;
  const checked = runNativeChecks(
    options,
    project,
    tsgoBinary,
    loaded.nativePlugins,
    checks,
  );
  if (checked.status !== 0) {
    return {
      result: checked,
      typescript: {},
    };
  }
  if (transformers.length === 0) {
    const transformed = transformProjectWithNativeHost(options, project);
    return {
      ...envelopeSideChannels(transformed),
      result: appendBuildOutput(checked, transformed.result),
      typescript: transformed.typescript,
    };
  }
  assertSharedHostCompatibility(transformers, "source-to-source");

  const plugin = selectSharedHostPlugin(transformers);
  const res = spawnNative(
    plugin.binary,
    createNativeTransformArgs(
      project,
      transformers,
      resolvePluginConfigDir(options),
    ),
    {
      cwd: project.root,
      env: nativePluginEnv(options, tsgoBinary, loaded.nativePlugins, plugin),
    },
  );
  if (res.error) {
    throw new Error(
      `ttsc.transform: failed to spawn ${plugin.binary}: ${res.error.message}`,
    );
  }
  const output = parseNativeTransformOutput(
    outputText(res.stdout),
    outputText(res.stderr),
  );
  const result = {
    diagnostics: output.diagnostics,
    status: res.status ?? 1,
    stdout: "",
    stderr: outputText(res.stderr),
  };
  return {
    ...envelopeSideChannels(output),
    result: appendBuildOutput(checked, result),
    typescript: output.typescript,
  };
}

/**
 * Collect the optional advisory envelope fields (`dependencies`,
 * `dependenciesComplete`, `graph`, `volatile`) into a spreadable object,
 * omitting absent fields so downstream result shapes stay free of `undefined`
 * keys.
 */
function envelopeSideChannels(output: {
  dependencies?: Record<string, string[]>;
  dependenciesComplete?: string[];
  graph?: ITtscCompilerTransformation.IReferenceGraph;
  volatile?: string[];
}): {
  dependencies?: Record<string, string[]>;
  dependenciesComplete?: string[];
  graph?: ITtscCompilerTransformation.IReferenceGraph;
  volatile?: string[];
} {
  return {
    ...(output.dependencies === undefined
      ? {}
      : { dependencies: output.dependencies }),
    ...(output.dependenciesComplete === undefined
      ? {}
      : { dependenciesComplete: output.dependenciesComplete }),
    ...(output.graph === undefined ? {} : { graph: output.graph }),
    ...(output.volatile === undefined ? {} : { volatile: output.volatile }),
  };
}

/**
 * Run every check-stage plugin in sequence, short-circuiting on the first
 * failure. Returns the aggregated `TtscBuildResult` (status 0 when all pass).
 */
function runNativeChecks(
  options: ITtscCompilerContext,
  project: ITtscParsedProjectConfig,
  tsgoBinary: string,
  nativePlugins: readonly ITtscLoadedNativePlugin[],
  checks: readonly ITtscLoadedNativePlugin[],
): TtscBuildResult {
  let result: TtscBuildResult = {
    diagnostics: [],
    status: 0,
    stdout: "",
    stderr: "",
  };
  for (const plugin of checks) {
    const res = spawnNative(
      plugin.binary,
      createNativeCheckArgs(
        project,
        nativePlugins,
        plugin,
        resolvePluginConfigDir(options),
      ),
      {
        cwd: project.root,
        env: nativePluginEnv(options, tsgoBinary, nativePlugins, plugin),
      },
    );
    if (res.error) {
      throw new Error(
        `ttsc.transform.check: failed to spawn ${plugin.binary}: ${res.error.message}`,
      );
    }
    result = appendBuildOutput(
      result,
      normalizeBuildOutput(
        {
          status: res.status ?? 1,
          stdout: outputText(res.stdout),
          stderr: outputText(res.stderr),
        },
        project.root,
      ),
    );
    if (result.status !== 0) {
      return result;
    }
  }
  return result;
}

/** Build the CLI argument list for the `transform` subcommand. */
function createNativeTransformArgs(
  project: ITtscParsedProjectConfig,
  plugins: readonly ITtscLoadedNativePlugin[],
  pluginConfigOrigin?: string,
): string[] {
  const args = [
    "transform",
    "--tsconfig=" + project.path,
    "--plugins-json=" + serializeNativePlugins(plugins),
    "--cwd=" + project.root,
  ];
  if (
    selectSharedHostPlugin(plugins).capabilities?.projectContextArgs === true
  ) {
    args.push(...createNativeProjectContextArgs(project, pluginConfigOrigin));
  }
  return args;
}

/** Build the CLI argument list for the `check` subcommand. */
function createNativeCheckArgs(
  project: ITtscParsedProjectConfig,
  plugins: readonly ITtscLoadedNativePlugin[],
  plugin: ITtscLoadedNativePlugin,
  pluginConfigOrigin?: string,
): string[] {
  const args = [
    "check",
    "--tsconfig=" + project.path,
    "--plugins-json=" + serializeNativePlugins(plugins),
    "--cwd=" + project.root,
  ];
  if (plugin.capabilities?.projectContextArgs === true) {
    args.push(...createNativeProjectContextArgs(project, pluginConfigOrigin));
  }
  return args;
}

/**
 * Serialize the plugin list to a JSON string for `--plugins-json=`. Only the
 * fields the native binary needs are included to keep the arg short.
 */
function serializeNativePlugins(
  plugins: readonly ITtscLoadedNativePlugin[],
): string {
  return JSON.stringify(
    plugins.map((plugin) => ({
      config: plugin.config,
      name: plugin.name,
      stage: plugin.stage,
    })),
  );
}

/**
 * Build the environment for a native plugin spawn. Injects `TTSC_NODE_BINARY`,
 * `TTSC_TSGO_BINARY`, and `TTSC_TTSX_BINARY` so the sidecar can re-invoke
 * Node.js or tsgo without searching PATH, plus `TTSC_PLUGIN_CONFIG_DIR` when
 * the caller declared a plugin config anchor (an embedder compiling through a
 * generated wrapper tsconfig) so config-file discovery walks the real project
 * instead of the wrapper's temp-dir ancestry. For transform plugins, also
 * passes `TTSC_LINKED_PLUGINS_JSON` when linked sources are present.
 */
function nativePluginEnv(
  options: ITtscCompilerContext,
  tsgoBinary: string,
  nativePlugins?: readonly ITtscLoadedNativePlugin[],
  plugin?: ITtscLoadedNativePlugin,
): NodeJS.ProcessEnv {
  const pluginConfigDir = resolvePluginConfigDir(options);
  const env: NodeJS.ProcessEnv = {
    ...process.env,
    TTSC_NODE_BINARY: process.env.TTSC_NODE_BINARY ?? process.execPath,
    ...(pluginConfigDir === undefined
      ? {}
      : { TTSC_PLUGIN_CONFIG_DIR: pluginConfigDir }),
    TTSC_TSGO_BINARY: process.env.TTSC_TSGO_BINARY ?? tsgoBinary,
    TTSC_TTSX_BINARY:
      process.env.TTSC_TTSX_BINARY ??
      path.join(__dirname, "..", "..", "launcher", "ttsx.js"),
    ...options.env,
  };
  // The anchor is per-invocation state owned by this host: when this run
  // declared none (and the caller's env does not name one), drop any value
  // inherited from an ancestor ttsc process so a nested build never
  // mis-anchors its plugins at the outer project.
  if (
    pluginConfigDir === undefined &&
    options.env?.TTSC_PLUGIN_CONFIG_DIR === undefined
  ) {
    delete env.TTSC_PLUGIN_CONFIG_DIR;
  }
  if (plugin?.stage === "transform") {
    const linked = linkedTransformPlugins(nativePlugins ?? []);
    if (linked.length !== 0) {
      env.TTSC_LINKED_PLUGINS_JSON = serializeNativePlugins(linked);
    }
  }
  return env;
}

/**
 * Parse the JSON envelope written by the native transform host to stdout.
 *
 * The `typescript` field must be a `Record<string, string>`. Any other shape is
 * treated as a protocol error and throws with the stderr/stdout context. JSON
 * parse errors are also wrapped with the same context message.
 *
 * The optional `dependencies`, `dependenciesComplete`, `graph`, and `volatile`
 * fields (see `ITtscCompilerTransformation`) are forwarded when well-formed;
 * entries that do not match the expected shape are dropped rather than failing
 * the transform — the fields are advisory invalidation metadata, not output.
 *
 * Dropping a malformed `dependenciesComplete` member is the safe direction on
 * purpose: an unlisted file keeps the sound host-owned bound, so a garbled
 * declaration costs over-invalidation, never a stale output.
 */
function parseNativeTransformOutput(
  stdout: string,
  stderr: string,
): {
  dependencies?: Record<string, string[]>;
  dependenciesComplete?: string[];
  diagnostics: ITtscCompilerDiagnostic[];
  graph?: ITtscCompilerTransformation.IReferenceGraph;
  typescript: Record<string, string>;
  volatile?: string[];
} {
  try {
    const parsed = JSON.parse(stdout) as {
      dependencies?: Record<string, string[]>;
      dependenciesComplete?: string[];
      diagnostics?: ITtscCompilerDiagnostic[];
      graph?: ITtscCompilerTransformation.IReferenceGraph;
      typescript?: Record<string, string>;
      volatile?: string[];
    };
    if (!isTextRecord(parsed.typescript)) {
      throw new Error(
        "ttsc: native transform host did not return a TypeScript source map",
      );
    }
    const dependencies = parseDependencyLists(parsed.dependencies);
    const dependenciesComplete = parseFileList(parsed.dependenciesComplete);
    const graph = parseReferenceGraph(parsed.graph);
    const volatile = parseFileList(parsed.volatile);
    return {
      ...(dependencies === undefined ? {} : { dependencies }),
      ...(dependenciesComplete === undefined ? {} : { dependenciesComplete }),
      ...(graph === undefined ? {} : { graph }),
      ...(volatile === undefined ? {} : { volatile }),
      diagnostics: Array.isArray(parsed.diagnostics) ? parsed.diagnostics : [],
      typescript: parsed.typescript,
    };
  } catch (error) {
    if (error instanceof Error && !(error instanceof SyntaxError)) {
      throw error;
    }
    throw new Error(
      (stderr || stdout).trim() ||
        "ttsc: native transform host returned no output",
    );
  }
}

/**
 * Normalize the optional `dependencies` envelope field into a record of string
 * arrays, or `undefined` when absent or carrying nothing usable.
 */
function parseDependencyLists(
  value: unknown,
): Record<string, string[]> | undefined {
  if (typeof value !== "object" || value === null || Array.isArray(value)) {
    return undefined;
  }
  const output: Record<string, string[]> = {};
  for (const [key, entries] of Object.entries(value)) {
    if (!Array.isArray(entries)) {
      continue;
    }
    const files = entries.filter(
      (entry): entry is string => typeof entry === "string",
    );
    if (files.length !== 0) {
      output[key] = files;
    }
  }
  return Object.keys(output).length === 0 ? undefined : output;
}

/**
 * Normalize the optional `graph` envelope section with the same tolerance as
 * `dependencies`: non-object sections are dropped, edge entries that are not
 * string arrays are dropped, and non-string list members are filtered. A
 * section carrying nothing usable collapses to `undefined`.
 */
function parseReferenceGraph(
  value: unknown,
): ITtscCompilerTransformation.IReferenceGraph | undefined {
  if (typeof value !== "object" || value === null || Array.isArray(value)) {
    return undefined;
  }
  const section = value as {
    configs?: unknown;
    edges?: unknown;
    globals?: unknown;
  };
  const edges = parseDependencyLists(section.edges) ?? {};
  const globals = parseFileList(section.globals) ?? [];
  const configs = parseFileList(section.configs) ?? [];
  if (
    Object.keys(edges).length === 0 &&
    globals.length === 0 &&
    configs.length === 0
  ) {
    return undefined;
  }
  return { configs, edges, globals };
}

/**
 * Normalize an optional string-list envelope field (`dependenciesComplete`,
 * `volatile`, and the `globals`/`configs` graph sections), or `undefined` when
 * absent or carrying nothing usable.
 */
function parseFileList(value: unknown): string[] | undefined {
  if (!Array.isArray(value)) {
    return undefined;
  }
  const files = value.filter(
    (entry): entry is string => typeof entry === "string" && entry.length !== 0,
  );
  return files.length === 0 ? undefined : files;
}

/** Type guard: true when `value` is a non-null, non-array object of strings. */
function isTextRecord(value: unknown): value is Record<string, string> {
  return (
    typeof value === "object" &&
    value !== null &&
    !Array.isArray(value) &&
    Object.values(value).every((entry) => typeof entry === "string")
  );
}

ttsc/src/flags/schema.ts:
// SOURCE-OF-TRUTH FLAG SCHEMA for the ttsc / ttsx command-line surface.
//
// One declaration per flag, consumed by every layer that needs to know about
// the flag:
//
//   * `packages/ttsc/src/flags/parser.ts`    — runtime TS parsing engine used
//                                              by `runTtsc.ts` and `runTtsx.ts`.
//   * `packages/ttsc/scripts/gen-flags.cjs`  — codegen that emits Go
//                                              allow-lists and the docs table.
//   * `packages/ttsc/cmd/ttsc/flags_gen.go`  — generated Go allow-list shared
//                                              by `cmd/ttsc/*.go` and
//                                              `utility/host.go`.
//   * `packages/lint/linthost/flags_gen.go`  — generated Go allow-list shared
//                                              by lint subcommand parsers.
//   * `website/src/content/docs/ttsc/flags.mdx` — generated reference table.
//
// The generator runs from `pnpm format`; its committed output is the spec the
// Go side reads, just like the `gen_shims:hand-maintained` pattern from
// AGENTS.md §2.1. Editing the generated files by hand is rejected by the
// `format` check.

/**
 * Subcommands the ttsc CLI dispatches to. The bare `"ttsc"` entry covers the
 * default lane (no explicit subcommand, e.g. `ttsc -p tsconfig.json`).
 */
export type TtscSubcommand =
  | "ttsc"
  | "build"
  | "check"
  | "fix"
  | "format"
  | "prepare"
  | "clean";

/**
 * Subcommands the ttsx CLI dispatches to. ttsx exposes a single lane today but
 * the schema mirrors ttsc's shape so future subcommands plug in without a
 * second engine.
 */
export type TtsxSubcommand = "ttsx";

export type AnySubcommand = TtscSubcommand | TtsxSubcommand;

/**
 * Layers a flag can be consumed by. The order reflects the runtime pipeline:
 *
 * Launcher → runBuild → tsgo / native sidecars (host, lint).
 *
 * A flag must declare at least one consumer. `forwardTo` declares where the
 * flag travels when the consuming layer does not absorb it (e.g. ttsc-owned
 * flags that the JS launcher consumes and re-emits as different tsgo flags).
 */
export type FlagLayer =
  | "launcher" // JS layer (`runTtsc.ts` / `runTtsx.ts`)
  | "runBuild" // JS layer (`runBuild.ts`) — internally adds the flag to tsgo
  | "tsgo" // tsgo binary (TypeScript-Go option parser)
  | "host" // native shared host (`utility/host.go`, `cmd/ttsc/build.go`)
  | "lint"; // native lint subcommand (`packages/lint/linthost/*.go`)

/**
 * Argument shape of a flag.
 *
 * - `boolean` — `--flag` / `--flag=true` / `--flag=false`. No value token is
 *   consumed.
 * - `value` — `--flag value` or `--flag=value`. Required value.
 * - `valueOptional` — `--flag` standalone is allowed; if followed by a non-flag
 *   token that token is consumed as the value. (Currently unused — declared for
 *   future flags like `--watch [path]`.)
 */
export type FlagKind = "boolean" | "value" | "valueOptional";

/**
 * Validation predicate for `value`-kind flags. `none` is the default (accept
 * any string).
 */
export type ValueValidator = "none" | "positiveInt";

/**
 * One CLI flag's complete contract. Every layer's behaviour is structural —
 * which subcommands accept the flag, where it is consumed, where it is
 * forwarded, whether it is terminal (prints and exits) — so the next layer
 * never silently drops the flag.
 */
export interface FlagSpec {
  /**
   * Canonical flag name including leading dashes (`"--singleThreaded"`). The
   * generator uses this as the map key in the Go allow-list and as the first
   * column of the docs table.
   */
  readonly name: string;

  /**
   * Alternative spellings (`"-p"`, `"--project"` for `--tsconfig`). The parsing
   * engine treats every alias as an equivalent of `name`.
   */
  readonly aliases?: readonly string[];

  /** Argument shape: boolean / required value / optional value. */
  readonly kind: FlagKind;

  /**
   * For `value` flags: optional validator. `positiveInt` mirrors the
   * `--checkers minValue:1` constraint tsgo enforces.
   */
  readonly validator?: ValueValidator;

  /** Subcommands that accept this flag. */
  readonly subcommands: readonly AnySubcommand[];

  /**
   * Layers that read the flag into a typed option. Order matters only for
   * documentation; the parsing engine merges across layers.
   */
  readonly consumedBy: readonly FlagLayer[];

  /**
   * Where the flag travels when the consuming layer does not absorb it. Default
   * for any flag a layer does not consume is `"tsgo"` — i.e. the launcher
   * forwards an unknown flag to tsgo via passthrough. Setting this to
   * `undefined` while `consumedBy: ["launcher"]` is set means the flag is
   * intentionally consumed-not-forwarded (e.g. ttsc-internal `--binary`).
   */
  readonly forwardTo?: FlagLayer;

  /**
   * Terminal flags ask the underlying tool to print something and exit
   * (`--help`, `--version`, `--showConfig`, `--listFilesOnly`, `--all`,
   * `--init`). ttsc must not wrap them in a pre-emit pass — that is how the
   * `--showConfig prints twice` bug appeared (RC-2).
   */
  readonly terminal?: boolean;

  /**
   * `true` when ttsc may add this flag to tsgo internally and post-process the
   * output. If the user also forwards the same flag, ttsc keeps the
   * user-visible behaviour (no double-print, no swallowed output). The shadow
   * check is structural rather than `passthrough.includes("…")`.
   *
   * Currently true for `--listEmittedFiles`, `--noEmit`, `--pretty`.
   */
  readonly internalShadow?: boolean;

  /**
   * Native sidecar capability that must be declared before ttsc sends this flag
   * as a bare CLI argument. Everything else routes through `--tsgo-args` or
   * stays in the JS launcher.
   */
  readonly nativeCapability?: "diagnosticsTiming" | "threadingArgs";

  /** Human description for `--help` and the docs table. */
  readonly description: string;
}

/**
 * Single source of truth for every flag the ttsc / ttsx CLI accepts. New flags
 * are added here and only here; the generator rebuilds the parsers and the Go
 * allow-lists from this table.
 *
 * Constraints enforced by the parser and the generator:
 *
 * 1. Every flag is uniquely identified by `name`; aliases must not collide with
 *    other flags' `name` or `aliases`.
 * 2. A flag listed in `consumedBy: ["launcher"]` without a `forwardTo`
 *    consumes-not-forwards. The generator flags this in the docs and the Go
 *    allow-list so the boundary is explicit.
 * 3. A flag with `subcommands` covering `clean` or `prepare` is parsed by the
 *    project-args lane; the parsing engine accepts the same flag in build /
 *    check / fix / format without a separate parser.
 */
export const FLAG_SCHEMA: readonly FlagSpec[] = [
  // -------------------------------------------------------------------------
  // ttsc — terminal flags (print and exit; never wrapped in pre-emit pass)
  // -------------------------------------------------------------------------
  {
    name: "--help",
    aliases: ["-h"],
    kind: "boolean",
    subcommands: ["ttsc", "ttsx", "build", "check", "fix", "format"],
    consumedBy: ["launcher"],
    terminal: true,
    description: "Show command help and exit.",
  },
  {
    name: "--version",
    aliases: ["-v"],
    kind: "boolean",
    subcommands: ["ttsc", "ttsx"],
    consumedBy: ["launcher"],
    terminal: true,
    description: "Print the launcher version and exit.",
  },

  // -------------------------------------------------------------------------
  // Project location: shared by every subcommand.
  // -------------------------------------------------------------------------
  {
    name: "--tsconfig",
    aliases: ["-p", "--project"],
    kind: "value",
    subcommands: [
      "ttsc",
      "ttsx",
      "build",
      "check",
      "fix",
      "format",
      "prepare",
      "clean",
    ],
    consumedBy: ["launcher", "host", "lint"],
    description: "Resolve project settings from this tsconfig.",
  },
  {
    name: "--cwd",
    kind: "value",
    subcommands: [
      "ttsc",
      "ttsx",
      "build",
      "check",
      "fix",
      "format",
      "prepare",
      "clean",
    ],
    consumedBy: ["launcher", "host", "lint"],
    description: "Resolve project-relative paths from this directory.",
  },

  // -------------------------------------------------------------------------
  // Emit / build mode.
  // -------------------------------------------------------------------------
  {
    name: "--emit",
    kind: "boolean",
    subcommands: ["ttsc", "build", "check"],
    consumedBy: ["launcher", "runBuild", "host", "lint"],
    description: "Force emitted files during build.",
  },
  {
    name: "--noEmit",
    kind: "boolean",
    subcommands: ["ttsc", "build", "check"],
    consumedBy: ["launcher", "runBuild", "host", "lint"],
    internalShadow: true,
    description: "Force analysis-only build with no file writes.",
  },
  {
    name: "--outDir",
    kind: "value",
    subcommands: ["ttsc", "build", "check"],
    consumedBy: ["launcher", "host", "lint"],
    description: "Override compilerOptions.outDir for this invocation.",
  },

  // -------------------------------------------------------------------------
  // Watch mode (launcher only).
  // -------------------------------------------------------------------------
  {
    name: "--watch",
    aliases: ["-w"],
    kind: "boolean",
    subcommands: ["ttsc", "build", "check"],
    consumedBy: ["launcher"],
    description: "Rebuild when project files change.",
  },
  {
    name: "--preserveWatchOutput",
    kind: "boolean",
    subcommands: ["ttsc", "build", "check"],
    consumedBy: ["launcher"],
    description: "Do not clear the screen between watch rebuilds.",
  },

  // -------------------------------------------------------------------------
  // Output verbosity.
  // -------------------------------------------------------------------------
  {
    name: "--quiet",
    kind: "boolean",
    subcommands: ["ttsc", "build", "check", "fix", "format"],
    consumedBy: ["launcher", "host", "lint"],
    description: "Keep build output quiet (default).",
  },
  {
    name: "--verbose",
    kind: "boolean",
    subcommands: ["ttsc", "build", "check", "fix", "format"],
    consumedBy: ["launcher", "host", "lint"],
    description: "Print the build summary and emitted files.",
  },

  // -------------------------------------------------------------------------
  // tsgo-binary / cache plumbing (consumed by launcher, not forwarded).
  // -------------------------------------------------------------------------
  {
    name: "--binary",
    kind: "value",
    subcommands: [
      "ttsc",
      "ttsx",
      "build",
      "check",
      "fix",
      "format",
      "prepare",
      "clean",
    ],
    consumedBy: ["launcher"],
    description: "Use an explicit tsgo binary.",
  },
  {
    name: "--cache-dir",
    kind: "value",
    subcommands: [
      "ttsc",
      "ttsx",
      "build",
      "check",
      "fix",
      "format",
      "prepare",
      "clean",
    ],
    consumedBy: ["launcher"],
    description: "Override the runner and source-plugin cache root.",
  },

  // -------------------------------------------------------------------------
  // Threading (tsgo-native; lint host opts in via capability).
  // -------------------------------------------------------------------------
  {
    name: "--singleThreaded",
    kind: "boolean",
    subcommands: ["ttsc", "ttsx", "build", "check", "fix", "format"],
    consumedBy: ["launcher", "runBuild", "tsgo", "host", "lint"],
    nativeCapability: "threadingArgs",
    description: "Run TypeScript-Go single-threaded (one checker).",
  },
  {
    name: "--checkers",
    kind: "value",
    validator: "positiveInt",
    subcommands: ["ttsc", "ttsx", "build", "check", "fix", "format"],
    consumedBy: ["launcher", "runBuild", "tsgo", "host", "lint"],
    nativeCapability: "threadingArgs",
    description: "Type-checker pool size (default: TypeScript-Go's).",
  },

  // -------------------------------------------------------------------------
  // ttsx-specific options.
  // -------------------------------------------------------------------------
  {
    name: "--require",
    aliases: ["-r"],
    kind: "value",
    subcommands: ["ttsx"],
    consumedBy: ["launcher"],
    description: "Preload a module before the entrypoint (ttsx).",
  },
  {
    name: "--no-plugins",
    kind: "boolean",
    subcommands: ["ttsx"],
    consumedBy: ["launcher"],
    description: "Build the project without ttsc plugins (ttsx).",
  },

  // -------------------------------------------------------------------------
  // tsgo-internal flags ttsc adds itself; users may also forward them.
  // Declaring them keeps the launcher's parser from treating them as
  // unknown forwarded flags whose value token gets misclassified.
  // -------------------------------------------------------------------------
  {
    name: "--listEmittedFiles",
    kind: "boolean",
    subcommands: ["ttsc", "build", "check"],
    consumedBy: ["runBuild", "tsgo"],
    forwardTo: "tsgo",
    internalShadow: true,
    description:
      "Print the list of emitted files (forwarded to tsgo; ttsc keeps the lines when forwarded).",
  },
  {
    name: "--pretty",
    kind: "value",
    subcommands: ["ttsc", "ttsx", "build", "check", "fix", "format"],
    consumedBy: ["tsgo"],
    forwardTo: "tsgo",
    internalShadow: true,
    description: "Toggle tsgo pretty-printed diagnostics (forwarded to tsgo).",
  },
  {
    name: "--diagnostics",
    kind: "boolean",
    subcommands: ["ttsc", "ttsx", "build", "check", "fix", "format"],
    consumedBy: ["runBuild", "tsgo", "lint"],
    forwardTo: "tsgo",
    nativeCapability: "diagnosticsTiming",
    description:
      "Print compiler performance information; plugin-backed ttsc runs add plugin wall-clock timings.",
  },
  {
    name: "--extendedDiagnostics",
    kind: "boolean",
    subcommands: ["ttsc", "ttsx", "build", "check", "fix", "format"],
    consumedBy: ["runBuild", "tsgo", "lint"],
    forwardTo: "tsgo",
    nativeCapability: "diagnosticsTiming",
    description:
      "Print detailed compiler performance information; plugin-backed ttsc runs add plugin wall-clock timings.",
  },
  {
    name: "--showConfig",
    kind: "boolean",
    subcommands: ["ttsc", "build", "check"],
    consumedBy: ["tsgo"],
    forwardTo: "tsgo",
    terminal: true,
    description: "Print the resolved tsconfig and exit (forwarded to tsgo).",
  },
  {
    name: "--listFilesOnly",
    kind: "boolean",
    subcommands: ["ttsc", "build", "check"],
    consumedBy: ["tsgo"],
    forwardTo: "tsgo",
    terminal: true,
    description: "Print the project file list and exit (forwarded to tsgo).",
  },
  {
    name: "--all",
    kind: "boolean",
    subcommands: ["ttsc", "build", "check"],
    consumedBy: ["tsgo"],
    forwardTo: "tsgo",
    terminal: true,
    description: "Print the full tsgo CLI help and exit.",
  },
  {
    name: "--init",
    kind: "boolean",
    subcommands: ["ttsc", "build", "check"],
    consumedBy: ["tsgo"],
    forwardTo: "tsgo",
    terminal: true,
    description: "Write a starter tsconfig.json and exit (forwarded to tsgo).",
  },

  // -------------------------------------------------------------------------
  // `--tsgo-args` — JSON-encoded passthrough envelope the launcher emits on
  // the way down to native sidecars. The sidecars decode it back into the
  // tsgo argv. Listed here so the schema describes every flag the Go layers
  // accept, not just the user-facing ones.
  // -------------------------------------------------------------------------
  {
    name: "--tsgo-args",
    kind: "value",
    subcommands: [
      "ttsc",
      "build",
      "check",
      "fix",
      "format",
      "prepare",
