import type { ITtscProjectPluginConfig } from "../ITtscProjectPluginConfig";

/**
 * Internal options shared by the CLI build, single-file emit, and runtime
 * paths.
 */
export interface TtscCommonOptions {
  /**
   * Explicit TypeScript-Go executable.
   *
   * When supplied, ttsc skips package-based tsgo resolution and shells out to
   * this binary directly.
   */
  binary?: string;
  /** Working directory for config discovery and relative file paths. */
  cwd?: string;
  /** Project root override for generated tsconfig wrappers. */
  projectRoot?: string;
  /**
   * Directory that anchors plugin config-file discovery and relative
   * `configFile` resolution (forwarded to plugin processes as
   * `TTSC_PLUGIN_CONFIG_DIR`). Set by build integrations that compile through a
   * generated tsconfig outside the project; when omitted, plugins anchor at the
   * tsconfig's own directory.
   */
  pluginConfigDir?: string;
  /** Environment variables merged over `process.env` for child processes. */
  env?: NodeJS.ProcessEnv;
  /** Explicit root directory for compiled source-plugin cache artifacts. */
  cacheDir?: string;
  /** Normalize compiler output so diagnostics can be parsed structurally. */
  structuredDiagnostics?: boolean;
  /**
   * Run TypeScript-Go single-threaded — one checker, serial parse/check/emit.
   * Mirrors `tsgo --singleThreaded`. Useful for deterministic debugging and CI
   * repro.
   */
  singleThreaded?: boolean;
  /**
   * Type-checker pool size, mirroring `tsgo --checkers`. `undefined` leaves
   * TypeScript-Go's default; ignored when `singleThreaded` is set.
   */
  checkers?: number;
  /**
   * CLI tokens ttsc did not recognize as its own, forwarded verbatim to the
   * underlying `tsgo` invocation. This is how a tsgo flag ttsc has no first-
   * class option for (`--strict`, `--target es2020`, `--listFiles`, …) still
   * reaches the compiler: ttsc owns its own flags and lets tsgo — which has the
   * complete, arity-aware option parser — handle the rest.
   */
  passthrough?: readonly string[];
  /**
   * Override project plugin loading for this invocation.
   *
   * - `false`: ignore `compilerOptions.plugins` completely.
   * - Array: use these plugin entries instead of the project config entries.
   * - `undefined`: use the project config entries as written.
   */
  plugins?: readonly ITtscProjectPluginConfig[] | false;
}

import type { ITtscCompilerDiagnostic } from "./ITtscCompilerDiagnostic";

/**
 * Result of a ttsc TypeScript-Go compilation operation.
 *
 * Represents the possible outcomes of {@link TtscCompiler.compile}, which can be
 * either a successful compilation, a compilation that completed with
 * diagnostics, or an unexpected host error during the compilation process.
 *
 * This type follows the legacy `embed-typescript` result model, but stores all
 * emitted text artifacts in {@link ITtscCompilerResult.ISuccess.output} and
 * {@link ITtscCompilerResult.IFailure.output}. TypeScript-Go may emit
 * JavaScript, declaration files, source maps, and declaration maps from one
 * compile operation, so the public result is not limited to JavaScript.
 *
 * @author Jeongho Nam - https://github.com/samchon
 */
export type ITtscCompilerResult =
  | ITtscCompilerResult.ISuccess
  | ITtscCompilerResult.IFailure
  | ITtscCompilerResult.IException;

export namespace ITtscCompilerResult {
  /**
   * Represents a successful ttsc compilation result.
   *
   * This interface is returned when TypeScript-Go completes without
   * diagnostics, containing every text output captured from the native compiler
   * host's `WriteFile` callback.
   */
  export interface ISuccess {
    /** Indicates that the compilation was successful. */
    type: "success";

    /** Non-fatal diagnostics reported during compilation. */
    diagnostics?: ITtscCompilerDiagnostic[];

    /**
     * The generated compiler output.
     *
     * A record mapping project-relative output file paths to their generated
     * text content. This includes JavaScript, declaration files, source maps,
     * declaration maps, and any other text artifact emitted through
     * TypeScript-Go's `WriteFile` callback.
     */
    output: Record<string, string>;
  }

  /**
   * Represents a ttsc compilation that completed with diagnostics or a
   * recoverable plugin failure.
   *
   * This interface is returned when the compiler reports errors, warnings, or
   * other diagnostics during normal compilation, or when a plugin failure can
   * be retained as a build result while an independent TypeScript check runs.
   * It contains both structured diagnostic information and any output that was
   * still generated despite the failure.
   */
  export interface IFailure {
    /** Indicates that compilation completed with diagnostics. */
    type: "failure";

    /** Array of diagnostic messages describing the compilation issues. */
    diagnostics: ITtscCompilerDiagnostic[];

    /**
     * Any compiler output that was generated despite the diagnostics.
     *
     * This may be partial or empty depending on the severity of the issues and
     * how far TypeScript-Go progressed before returning diagnostics.
     */
    output: Record<string, string>;
  }

  /**
   * Represents an unexpected error during the compilation process.
   *
   * This interface is returned when ttsc cannot prepare, build, or spawn the
   * native compiler host. Normal TypeScript diagnostics are represented by
   * {@link IFailure}; this variant is reserved for host-level exceptions.
   */
  export interface IException {
    /** Indicates that an unexpected host error occurred. */
    type: "exception";

    /**
     * Optional classifier so embedders can branch on the failure mode without
     * pattern-matching error messages. Omitted when ttsc cannot determine the
     * origin. Treat as `"unknown"` when missing.
     *
     * - `"plugin"`: plugin preparation failed before a build result could be
     *   recovered.
     * - `"host"`: the TypeScript-Go host could not start (missing binary, cache
     *   lock, invalid config).
     * - `"unknown"`: any other host-level failure.
     */
    kind?: "plugin" | "host" | "unknown";

    /** The error that was thrown while preparing or running the compiler host. */
    error: unknown;
  }
}

ttsc/src/structures/ITtscCompilerTransfo:
import type { ITtscCompilerDiagnostic } from "./ITtscCompilerDiagnostic";

/**
 * Result of a TypeScript source-to-source transformation operation.
 *
 * This mirrors `embed-typescript`'s `IEmbedTypeScriptTransformation` model.
 * Unlike {@link ITtscCompilerResult}, this contract is not an emit contract: the
 * `typescript` map must contain TypeScript source text, not generated
 * JavaScript, declaration files, or source maps.
 */
export type ITtscCompilerTransformation =
  | ITtscCompilerTransformation.ISuccess
  | ITtscCompilerTransformation.IFailure
  | ITtscCompilerTransformation.IException;

export namespace ITtscCompilerTransformation {
  /**
   * Host-owned reference graph of the transformed program, mirroring the
   * envelope's optional `graph` section.
   *
   * The graph is the language-semantic input bound of the transform under `tsc
   * --incremental` semantics: any symbol a file can reference is reachable
   * through its import/reference closure or is ambient. Bundler adapters
   * register, per transformed file `F`, the reachability closure of
   * {@link edges} from `F` together with {@link globals} and {@link configs}, so
   * persistent caches and watch graphs invalidate soundly without per-plugin
   * dependency reporting.
   *
   * Keys and values follow the same convention as {@link ISuccess.typescript}:
   * project-relative slash paths, falling back to absolute slash paths outside
   * the project root.
   */
  export interface IReferenceGraph {
    /**
     * Direct resolved references per file: imports, re-exports, `///
     * <reference>` targets, and type reference directives — type-only edges
     * included. Direct edges only; consumers compute transitive reachability
     * themselves.
     */
    edges: Record<string, string[]>;

    /**
     * Files contributing to the global scope (ambient declaration files, script
     * files, global augmentations, `typeRoots` entries). A change to any of
     * them can affect every file in the program.
     */
    globals: string[];

    /** The project tsconfig followed by its `extends` ancestry. */
    configs: string[];
  }

  /** Successful source-to-source transformation result. */
  export interface ISuccess {
    /** Indicates that transformation completed without diagnostics. */
    type: "success";

    /** Non-fatal diagnostics reported during transformation. */
    diagnostics?: ITtscCompilerDiagnostic[];

    /**
     * Transformed TypeScript source text keyed by project-relative file path.
     *
     * Values are TypeScript source text, never JavaScript, declaration files,
     * or source maps. When no transform native source is configured, this map
     * contains the unmodified TypeScript files loaded by the TypeScript-Go
     * Program.
     */
    typescript: Record<string, string>;

    /**
     * Source files the transform consulted per transformed file, keyed the same
     * way as {@link typescript}. Each entry lists the project-relative or
     * absolute paths whose content influenced that output beyond the file
     * itself — e.g. the declaration files a type-driven code generator read.
     *
     * Optional: only present when the transform native source reported a
     * `dependencies` object in its stdout envelope. Bundler adapters use it to
     * register watch files so type-only imports participate in HMR
     * invalidation. ttsc passes the paths through verbatim.
     */
    dependencies?: Record<string, string[]>;

    /**
     * Transformed files (keyed like {@link typescript}) whose
     * {@link dependencies} entry the transform host declares **complete**: every
     * input beyond the file itself and the universal
     * {@link IReferenceGraph.configs} chain is listed there.
     *
     * The declaration narrows invalidation. For a listed file a consumer uses
     * `dependencies[F] ∪ graph.configs` instead of the union with the
     * host-owned `reach(graph.edges, F) ∪ graph.globals` bound, so a change to
     * a file the transform never consulted no longer re-runs it. Unlisted files
     * keep the union, so a mixed envelope composes per file.
     *
     * This is a responsibility transfer, not a hint: an omission makes the
     * consumer serve stale output, and that is a defect of the declaring plugin
     * rather than of the host. Producers list a file only when the reported set
     * is derived from what the transform actually consulted (a Checker-driven
     * generator's per-file consulted-declaration list). When several plugin
     * entries contribute to one file, the envelope's author may list it only if
     * every contributing entry declared its own list complete for it.
     *
     * The config chain a listed file keeps is {@link graph}'s, so a host that
     * declares completeness should stamp {@link graph} too; without it a listed
     * file retains no universal input at all.
     *
     * Optional, and never required for correctness: an envelope without this
     * field keeps the sound host-owned bound. A file that is both listed here
     * and in {@link volatile} keeps the union, since the two claims contradict
     * and the conservative one wins.
     */
    dependenciesComplete?: string[];

    /**
     * Host-owned reference graph of the transformed program.
     *
     * Optional: only present when the transform host stamped a `graph` section
     * into its stdout envelope (the built-in native host and the linked-plugin
     * host always do; external sidecars adopt through the driver SDK).
     * Malformed sections are dropped, never fatal — the field is advisory
     * invalidation metadata, not output.
     */
    graph?: IReferenceGraph;

    /**
     * Transformed files (keyed like {@link typescript}) whose output depends on
     * non-file inputs (environment, time, network) as declared by the transform
     * plugin via the envelope's optional `volatile` list. No file-dependency
     * scheme can represent such inputs, so consumers must exclude these files
     * from caching instead of watching more files.
     */
    volatile?: string[];
  }

  /** Source-to-source transformation result that completed with diagnostics. */
  export interface IFailure {
    /** Indicates that transformation completed with diagnostics. */
    type: "failure";

    /**
     * Transformed or partially transformed TypeScript source text keyed by
     * project-relative file path.
     *
     * May be empty or partial when diagnostics prevented the transform native
     * source from completing its pass.
     */
    typescript: Record<string, string>;

    /** Diagnostics reported during transformation. */
    diagnostics: ITtscCompilerDiagnostic[];

    /**
     * Source files the transform consulted per transformed file. Same shape and
     * semantics as {@link ISuccess.dependencies}; may be partial when the
     * transform did not complete its pass.
     */
    dependencies?: Record<string, string[]>;

    /**
     * Files whose reported dependency list the host declares complete. Same
     * shape and semantics as {@link ISuccess.dependenciesComplete}; may be
     * partial when the transform did not complete its pass.
     */
    dependenciesComplete?: string[];

    /**
     * Host-owned reference graph. Same shape and semantics as
     * {@link ISuccess.graph}; may be absent when diagnostics prevented the host
     * from loading the program.
     */
    graph?: IReferenceGraph;

    /**
     * Volatile transformed files. Same shape and semantics as
     * {@link ISuccess.volatile}.
     */
    volatile?: string[];
  }

  /** Unexpected host-level error during transformation. */
  export interface IException {
    /** Indicates that transformation could not complete normally. */
    type: "exception";

    /**
     * Optional classifier so embedders can branch on the failure mode without
     * pattern-matching error messages. Omitted when ttsc cannot determine the
     * origin. Treat as `"unknown"` when missing.
     *
     * - `"plugin"`: a native plugin sidecar crashed or exited non-zero.
     * - `"host"`: the TypeScript-Go host could not start (missing binary, cache
     *   lock, invalid config).
     * - `"unknown"`: any other host-level failure.
     */
    kind?: "plugin" | "host" | "unknown";

    /** Raw error thrown by the ttsc host. */
    error: unknown;
  }
}

ttsc/src/TtscCompiler.ts:
import fs from "node:fs";
import path from "node:path";

import { compileProjectInMemory } from "./compiler/internal/compileProjectInMemory";
import { resolveProjectConfig } from "./compiler/internal/project/resolveProjectConfig";
import { resolveBinary } from "./compiler/internal/resolveBinary";
import { createProcessDiagnostic } from "./compiler/internal/runBuild";
import { transformProjectInMemory } from "./compiler/internal/transformProjectInMemory";
import { resolveCleanTargets } from "./plugin/internal/buildSourcePlugin";
import { loadProjectPlugins } from "./plugin/internal/loadProjectPlugins";
import type { ITtscCompilerContext } from "./structures/ITtscCompilerContext";
import type { ITtscCompilerDiagnostic } from "./structures/ITtscCompilerDiagnostic";
import type { ITtscCompilerResult } from "./structures/ITtscCompilerResult";
import type { ITtscCompilerTransformation } from "./structures/ITtscCompilerTransformation";
import type { TtscBuildResult } from "./structures/internal/TtscBuildResult";

/**
 * Programmatic compiler host for the `ttsc` TypeScript-Go pipeline.
 *
 * `TtscCompiler` is the root JavaScript API exported by the `ttsc` package. It
 * represents one resolved project context: a working directory, an optional
 * project config path, an optional native toolchain override, an environment, a
 * cache root, and a plugin list. Those values are captured by the constructor
 * and are intentionally not replaceable per method call.
 *
 * The class exposes only the operations that make sense for an embedded
 * compiler host:
 *
 * - {@link TtscCompiler.prepare}: build configured Go source plugins into the
 *   cache before a later compile.
 * - {@link TtscCompiler.clean}: remove the cache owned by this compiler context.
 * - {@link TtscCompiler.compile}: compile the configured project and return a
 *   structured result instead of terminal text.
 * - {@link TtscCompiler.transform}: transform the configured project and return an
 *   embed-style transformation result.
 */
export class TtscCompiler {
  private readonly context: ITtscCompilerContext;

  /**
   * Create a new compiler instance bound to the given project context.
   *
   * The context is defensively copied: mutations to the original object after
   * construction do not affect this instance. Omit `context` (or pass `{}`) to
   * inherit all defaults from the running process.
   */
  public constructor(context: ITtscCompilerContext = {}) {
    this.context = {
      ...context,
      env: context.env ? { ...context.env } : undefined,
      plugins: Array.isArray(context.plugins)
        ? [...context.plugins]
        : context.plugins,
    };
  }

  /**
   * Build every configured source plugin into the instance cache.
   *
   * This method loads the project plugin descriptors, resolves their
   * {@link ITtscPlugin.source} paths, and compiles those Go command packages
   * into the ttsc cache. It is useful when a host application wants to pay the
   * lazy build cost before the first compile call.
   *
   * `prepare()` is not a project check. It does not create a TypeScript-Go
   * Program, does not run diagnostics, and does not emit output files.
   *
   * @returns Compiled native plugin binary paths.
   */
  public prepare(): string[] {
    const execution = this.resolveProjectExecution();
    const loaded = loadProjectPlugins({
      binary: resolveBinary(this.compilerContext()) ?? "",
      cacheDir: this.resolvePluginCacheDir(),
      cwd: execution.cwd,
      entries: this.context.plugins,
      env: this.resolveEffectiveEnv(),
      pluginConfigDir: this.context.pluginConfigDir,
      projectRoot: execution.projectRoot,
      tsconfig: execution.tsconfig,
    });
    return loaded.nativePlugins.map((plugin) => plugin.binary);
  }

  /**
   * Remove compiled cache artifacts for this compiler instance.
   *
   * Removes the resolved cache root (which holds both the plugin binaries and,
   * when ttsc-owned, the Go build cache), a ttsc-owned Go build cache that
   * lives outside that root (`TTSC_GO_CACHE_DIR`), and the two legacy
   * project-local caches. A user-provided `GOCACHE` is never removed. The cache
   * location comes from this instance's `cacheDir` and environment
   * (`TTSC_CACHE_DIR` / `TTSC_GO_CACHE_DIR`), defaulting to
   * `<workspaceRoot>/node_modules/.cache/ttsc`.
   *
   * @returns Cache directories that were removed.
   */
  public clean(): string[] {
    const projectRoot = this.resolveCleanProjectRoot();
    const legacyTargets = [
      path.join(projectRoot, "node_modules", ".ttsc"),
      path.join(projectRoot, ".ttsc"),
    ];
    const explicitCacheDir = this.resolveCacheDir();
    if (explicitCacheDir !== undefined) {
      // An explicit constructor `cacheDir` names the cache directory for this
      // instance — exactly like `ttsc clean --cache-dir X` on the CLI — so
      // remove it wholesale plus the legacy project-local caches. This keeps
      // the programmatic and CLI clean contracts identical for an explicit
      // cache dir.
      return removeExistingDirectories([explicitCacheDir, ...legacyTargets]);
    }
    // Default / `context.env.TTSC_CACHE_DIR`: resolve the cache root and the Go
    // build cache (`TTSC_GO_CACHE_DIR`) from this instance's effective
    // environment — the same `{ ...process.env, ...context.env }` that
    // prepare()/compile()/transform() build with — then remove only the
    // ttsc-owned subdirectories, so a possibly-shared root is never deleted and
    // a user-provided `GOCACHE` is never touched. Using the effective env (not
    // ambient `process.env`) makes clean() remove exactly the artifacts this
    // instance owns, including a `TTSC_GO_CACHE_DIR` supplied only in
    // `context.env`.
    return removeExistingDirectories(
      resolveCleanTargets(
        projectRoot,
        this.resolvePluginCacheDir(),
        this.resolveEffectiveEnv(),
      ),
    );
  }

  /**
   * Compile the configured project.
   *
   * The public API does not write emitted files into the caller's project tree.
   * For projects without plugins, ttsc uses its native TypeScript-Go host's
   * `WriteFile` callback to capture output in memory. For projects with native
   * plugins, ttsc runs the plugin pipeline against a temporary output
   * directory, reads the generated text artifacts, and removes the temporary
   * directory before returning.
   *
   * The result uses an `embed-typescript`-style discriminated union: `success`
   * for clean compiles, `failure` for compiler diagnostics or plugin failures
   * that reached the build pipeline, and `exception` for host failures that
   * prevent any project check from running.
   *
   * @returns Structured compilation result containing diagnostics or output.
   */
  public compile(): ITtscCompilerResult {
    return runProject(() => compileProjectInMemory(this.compilerContext()));
  }

  /**
   * Transform the configured project and return TypeScript text by file path.
   *
   * This is the source-to-source API for plugin authors. It must not return
   * JavaScript emit, declaration files, or source maps; those artifacts belong
   * to {@link TtscCompiler.compile}. A transform native source is expected to
   * write JSON shaped as `{ "typescript": { "src/file.ts": "..." } }` to
   * stdout. When no transform native source is configured, ttsc returns the
   * TypeScript files loaded by the TypeScript-Go Program together with normal
   * diagnostics.
   *
   * The returned shape mirrors `embed-typescript`'s transformation API:
   * `success` and `failure` carry a `typescript` map, while unexpected host
   * errors return `exception`.
   *
   * @returns Transformation result containing TypeScript text or diagnostics.
   */
  public transform(): ITtscCompilerTransformation {
    return runTransformation(() =>
      transformProjectInMemory(this.compilerContext()),
    );
  }

  private compilerContext(): ITtscCompilerContext {
    return {
      ...this.context,
      cacheDir: this.resolveCacheDir(),
    };
  }

  private resolveProjectExecution(): {
    cwd: string;
    projectRoot: string;
    tsconfig: string;
  } {
    const cwd = this.resolveCwd();
    const tsconfig = resolveProjectConfig({
      cwd,
      tsconfig: this.context.tsconfig,
    });
    return {
      cwd,
      projectRoot: this.context.projectRoot
        ? path.resolve(cwd, this.context.projectRoot)
        : path.dirname(tsconfig),
      tsconfig,
    };
  }

  private resolveCleanProjectRoot(): string {
    try {
      return this.resolveProjectExecution().projectRoot;
    } catch (error) {
      if (this.context.tsconfig) {
        throw error;
      }
      return this.resolveCwd();
    }
  }

  private resolveCwd(): string {
    return path.resolve(this.context.cwd ?? process.cwd());
  }

  private resolveCacheDir(): string | undefined {
    if (!this.context.cacheDir) {
      return undefined;
    }
    return path.isAbsolute(this.context.cacheDir)
      ? this.context.cacheDir
      : path.resolve(this.resolveCwd(), this.context.cacheDir);
  }

  private resolvePluginCacheDir(): string | undefined {
    return this.resolveCacheDir() ?? this.context.env?.TTSC_CACHE_DIR;
  }

  /**
   * The effective environment for this instance's source-plugin builds and
   * clean targets: `context.env` merged over `process.env`, matching the
   * documented {@link ITtscCompilerContext.env} contract that child compiler,
   * native-plugin, and native-host processes already receive. Returned as a
   * fresh object so callers never mutate the shared `process.env`; when no
   * `context.env` was supplied this is a plain copy of `process.env`, so CLI /
   * default behavior is unchanged.
   */
  private resolveEffectiveEnv(): NodeJS.ProcessEnv {
    return { ...process.env, ...this.context.env };
  }
}

function removeExistingDirectories(directories: readonly string[]): string[] {
  const removed: string[] = [];
  for (const directory of [...new Set(directories)]) {
    if (!fs.existsSync(directory)) {
      continue;
    }
    fs.rmSync(directory, { recursive: true, force: true });
    removed.push(directory);
  }
  return removed;
}

interface ProjectResult {
  output: Record<string, string>;
  result: TtscBuildResult;
}

interface ProjectTransformation {
  dependencies?: Record<string, string[]>;
  dependenciesComplete?: string[];
  graph?: ITtscCompilerTransformation.IReferenceGraph;
  result: TtscBuildResult;
  typescript: Record<string, string>;
  volatile?: string[];
}

function runProject(task: () => ProjectResult): ITtscCompilerResult {
  try {
    return toCompilerResult(task());
  } catch (error) {
    return {
      error: normalizeError(error),
      kind: classifyException(error),
      type: "exception",
    };
  }
}

function runTransformation(
  task: () => ProjectTransformation,
): ITtscCompilerTransformation {
  try {
    return toCompilerTransformation(task());
  } catch (error) {
    return {
      error: normalizeError(error),
      kind: classifyException(error),
      type: "exception",
    };
  }
}

/**
 * Best-effort classifier for the `kind` field of `IException`. Pattern- matches
 * the real prefixes thrown inside this package:
 *
 * - Plugin: messages from `loadProjectPlugins.ts` / `buildSourcePlugin.ts` start
 *   with `ttsc: plugin "..."` or `ttsc: package "..." declares ...`, and
 *   transform-time spawn failures start with `ttsc.transform:` /
 *   `ttsc.transform.check:`. The Go-toolchain missing envelope also surfaces
 *   here.
 * - Host: everything else under the `ttsc:` umbrella — the bare `ttsc:` strings
 *   from `paths.ts`, `ttsc: TypeScript-Go executable not found`
 *   (`resolveTsgo.ts`), `ttsc: failed to spawn native compiler host`
 *   (`transformProjectInMemory.ts`), and tsconfig / extended-tsconfig shapes
 *   from `readProjectConfig.ts`.
 * - Anything else falls back to `"unknown"` so embedders always see the field set
 *   per the documented contract.
 *
 * Order matters: plugin patterns must run before the generic `ttsc:` test
 * because every plugin message also starts with `ttsc:`.
 */
function classifyException(error: unknown): "plugin" | "host" | "unknown" {
  const message =
    error instanceof Error
      ? error.message
      : typeof error === "string"
        ? error
        : "";
  if (
    // Match every plugin-origin shape with verb-anchored patterns so a
    // host-path containing the literal token `plugin` (e.g.
    // `TTSC_BINARY=/opt/cache/plugins/ttsc-bin`) does not misclassify
    // as kind="plugin". Each alternative anchors at the start of the
    // message to capture the verb, not anywhere later in the line:
    //
    //   - `ttsc: plugin "..."` / `ttsc: package "..."` — from
    //     loadProjectPlugins.ts
    //   - `ttsc: building plugin "..."` / `ttsc: reading go.mod for
    //     plugin "..."` — from buildSourcePlugin.ts
    //   - `ttsc.transform:` / `ttsc.transform.check:` — from
    //     transformProjectInMemory.ts
    //   - `ttsc-plugin:` — legacy prefix kept for compatibility
    //   - `go toolchain` — the goToolchainNotFoundMessage envelope
    /^ttsc:\s*plugin\b|^ttsc:\s*package\b|^ttsc:\s*building plugin\b|^ttsc:\s*reading go\.mod for plugin\b|^ttsc\.transform[.:]|^ttsc-plugin:|go toolchain/i.test(
      message,
    )
  ) {
    return "plugin";
  }
  if (
    /^ttsc:|tsconfig|extended tsconfig|TypeScript-Go|native compiler host/i.test(
      message,
    )
  ) {
    return "host";
  }
  return "unknown";
}

function toCompilerResult(project: ProjectResult): ITtscCompilerResult {
  const { output, result } = project;
  if (result.status === 0 && !hasErrorDiagnostics(result.diagnostics)) {
    return {
      ...(result.diagnostics.length === 0
        ? {}
        : { diagnostics: result.diagnostics }),
      output,
      type: "success",
    };
  }
  return {
    diagnostics:
      result.diagnostics.length === 0
        ? [createProcessDiagnostic(result)]
        : result.diagnostics,
    output,
    type: "failure",
  };
}

function toCompilerTransformation(
  project: ProjectTransformation,
): ITtscCompilerTransformation {
  const {
    dependencies,
    dependenciesComplete,
    graph,
    result,
    typescript,
    volatile,
  } = project;
  const advisoryFields = {
    ...(dependencies === undefined ? {} : { dependencies }),
    ...(dependenciesComplete === undefined ? {} : { dependenciesComplete }),
    ...(graph === undefined ? {} : { graph }),
    ...(volatile === undefined ? {} : { volatile }),
  };
  if (result.status === 0 && !hasErrorDiagnostics(result.diagnostics)) {
    return {
      ...(result.diagnostics.length === 0
        ? {}
        : { diagnostics: result.diagnostics }),
      ...advisoryFields,
      type: "success",
      typescript,
    };
  }
  return {
    ...advisoryFields,
    diagnostics:
      result.diagnostics.length === 0
        ? [createProcessDiagnostic(result)]
        : result.diagnostics,
    type: "failure",
    typescript,
  };
}

function hasErrorDiagnostics(
  diagnostics: readonly ITtscCompilerDiagnostic[],
): boolean {
  return diagnostics.some((diagnostic) => diagnostic.category === "error");
}

function normalizeError(error: unknown): unknown {
  if (!(error instanceof Error)) {
    return error;
  }
  return {
    message: error.message,
    name: error.name,
    stack: error.stack,
  };
}

